function debounce(fn, delay, options = {}) {
  let timer = null;
  let lastArgs = null;
  let lastThis = null;
  let lastResult = null;

  const { leading = false, trailing = true, maxWait } = options;

  const startTimer = (timestamp) => {
    timer = setTimeout(() => {
      timer = null;
      if (trailing && lastArgs !== null) {
        lastResult = fn.apply(lastThis, lastArgs);
        lastArgs = null;
        lastThis = null;
      }
    }, Math.max(0, delay - (timestamp - startTime)));
  };

  let startTime;

  const debounced = function (...args) {
    const context = this;
    const now = Date.now();

    if (timer === null) {
      if (leading) {
        lastResult = fn.apply(context, args);
      }
      startTime = now;
      startTimer(now);
    } else {
      lastArgs = args;
      lastThis = context;
      if (maxWait !== undefined && now - startTime >= maxWait) {
        clearTimeout(timer);
        lastResult = fn.apply(context, args);
        lastArgs = null;
        lastThis = null;
        startTime = now;
        startTimer(now);
      }
    }

    return lastResult;
  };

  debounced.cancel = function () {
    if (timer !== null) {
      clearTimeout(timer);
      timer = null;
    }
    lastArgs = null;
    lastThis = null;
  };

  debounced.flush = function () {
    if (timer !== null) {
      clearTimeout(timer);
      if (lastArgs !== null) {
        lastResult = fn.apply(lastThis, lastArgs);
        lastArgs = null;
        lastThis = null;
      }
      timer = null;
    }
    return lastResult;
  };

  debounced.pending = function () {
    return timer !== null;
  };

  return debounced;
}
```

使用示例：

```javascript
// 基础用法
const onSearch = debounce((query) => {
  console.log('搜索:', query);
}, 300);

// 带立即执行（首次触发立即执行，后续防抖）
const onResize = debounce(() => {
  console.log('尺寸变化');
}, 200, { leading: true });

// 带最大等待时间，确保高频触发下也能及时执行
const onSave = debounce((data) => {
  console.log('保存:', data);
}, 1000, { maxWait: 5000 });

// 取消
onSearch.cancel();

// 立即执行待处理的回调
onSearch.flush();
```

关键设计点：
- `leading`：首次触发是否立即执行
- `trailing`：防抖结束后是否执行最后一次
- `maxWait`：强制上限，防止长时间不执行
- `cancel` / `flush` / `pending`：提供完整的生命周期控制

